                            </h3>
                            <div className="flex items-center gap-2 text-[10px] font-bold text-slate-500 mt-0.5">
                                <span>Total: {activeSummary.count}</span>
                                <span className="w-px h-2 bg-slate-300"></span>
                                <span className={`${activeCategory === 'expenses' ? 'text-red-600' : 'text-emerald-600'}`}>
                                    {formatCurrency(activeSummary.total, language)}
                                </span>
                            </div>
                        </div>
                    </div>

                    {/* Stats Pills & Search (Compact) */}
                    <div className="flex items-center gap-2 overflow-x-auto no-scrollbar">
                        <div className="flex gap-2">
                            {/* AUTO PILL */}
                            <div className="flex items-center gap-2 px-2.5 py-1 bg-emerald-50 text-emerald-700 border border-emerald-100 rounded-lg">
                                <div className="flex flex-col leading-none">
                                    <span className="text-[8px] font-black uppercase tracking-wide opacity-70">Auto</span>
                                    <span className="text-[10px] font-bold">{activeSummary.auto}</span>
                                </div>
                                <span className="text-[10px] font-bold font-mono text-emerald-800 border-l border-emerald-200 pl-2">
                                    {formatCurrency(activeSummary.autoValue, language)}
                                </span>
                            </div>

                            {/* MANUAL PILL */}
                            <div className="flex items-center gap-2 px-2.5 py-1 bg-blue-50 text-blue-700 border border-blue-100 rounded-lg">
                                <div className="flex flex-col leading-none">
                                    <span className="text-[8px] font-black uppercase tracking-wide opacity-70">Manual</span>
                                    <span className="text-[10px] font-bold">{activeSummary.manual}</span>
                                </div>
                                <span className="text-[10px] font-bold font-mono text-blue-800 border-l border-blue-200 pl-2">
                                    {formatCurrency(activeSummary.manualValue, language)}
                                </span>
                            </div>

                            {/* PENDING PILL */}
                            {activeSummary.pending > 0 && (
                                <div className="flex items-center gap-2 px-2.5 py-1 bg-amber-50 text-amber-700 border border-amber-100 rounded-lg">
                                    <div className="flex flex-col leading-none">
                                        <span className="text-[8px] font-black uppercase tracking-wide opacity-70">Pend</span>
                                        <span className="text-[10px] font-bold">{activeSummary.pending}</span>
                                    </div>
                                    <span className="text-[10px] font-bold font-mono text-amber-800 border-l border-amber-200 pl-2">
                                        {formatCurrency(activeSummary.pendingValue, language)}
                                    </span>
                                </div>
                            )}
                        </div>

                        <div className="w-px h-6 bg-slate-200 dark:bg-slate-700 mx-1 hidden md:block"></div>

                        <div className="relative group">
                            <MagnifyingGlassIcon className="w-3 h-3 text-slate-400 absolute left-2 top-1/2 -translate-y-1/2 group-focus-within:text-brand-blue transition-colors" />
                            <input 
                                type="text" 
                                placeholder="Pesquisar..." 
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="pl-7 pr-2 py-1 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-600 rounded-lg text-[10px] font-medium focus:ring-1 focus:ring-brand-blue/30 focus:border-brand-blue outline-none w-24 focus:w-40 transition-all"
                            />
                        </div>
                    </div>
                </div>

                {/* 3.2. Table Area (Takes remaining space) */}
                <div className="flex-1 min-h-0 relative">
                    {sortedData.length > 0 ? (
                        <div className="absolute inset-0">
                            <EditableReportTable 
                                data={sortedData}
                                onRowChange={handleRowChange}
                                reportType={activeReportType}
                                sortConfig={sortConfig}
                                onSort={handleSort}
                                loadingAiId={loadingAiId}
                                onEdit={handleEdit}
                            />
                        </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-full text-slate-400">
                            <p className="text-xs italic">Nenhum dado encontrado para esta seleção.</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

import React, { createContext, useState, useMemo, useCallback, useEffect, useRef } from 'react';
import { useAuth } from './AuthContext';
import { useUI } from './UIContext';
import { useReferenceData } from '../hooks/useReferenceData';
import { useReconciliation } from '../hooks/useReconciliation';
import { useReportManager } from '../hooks/useReportManager';
import { usePersistentState } from '../hooks/usePersistentState';
import {
    Transaction, Contributor, MatchResult, Bank, Church, ChurchFormData,
    DeletingItem, ComparisonType, GroupedReportData, SearchFilters, SavedReport,
    SavingReportState, LearnedAssociation, MatchMethod, FileModel, SpreadsheetData
} from '../types';
import { groupResultsByChurch, PLACEHOLDER_CHURCH } from '../services/processingService';

import { supabase } from '../services/supabaseClient';
import { useTranslation } from './I18nContext';
import { LoadingSpinner } from '../components/shared/LoadingSpinner';
import { RecompareModal } from '../components/modals/RecompareModal';

interface AppContextType {
    // Data State (from useReferenceData)
    banks: Bank[];
    churches: Church[];
    fileModels: FileModel[];
    fetchModels: () => Promise<void>;
    setBanks: React.Dispatch<React.SetStateAction<Bank[]>>;
    setChurches: React.Dispatch<React.SetStateAction<Church[]>>;
    similarityLevel: number;
    setSimilarityLevel: React.Dispatch<React.SetStateAction<number>>;
    dayTolerance: number;
    setDayTolerance: React.Dispatch<React.SetStateAction<number>>;
    customIgnoreKeywords: string[]; 
    effectiveIgnoreKeywords: string[]; 
    addIgnoreKeyword: (keyword: string) => void;
    removeIgnoreKeyword: (keyword: string) => void;
    contributionKeywords: string[];
    addContributionKeyword: (keyword: string) => void;
    removeContributionKeyword: (keyword: string) => void;
    learnedAssociations: LearnedAssociation[];

    // Edit States
    editingBank: Bank | null;
    editingChurch: Church | null;
    openEditBank: (bank: Bank) => void;
    closeEditBank: () => void;
    updateBank: (bankId: string, name: string) => void;
    addBank: (name: string) => Promise<boolean>;
    openEditChurch: (church: Church) => void;
    closeEditChurch: () => void;
    updateChurch: (churchId: string, data: ChurchFormData) => void;
    addChurch: (data: ChurchFormData) => Promise<boolean>;

    // Reconciliation State (from useReconciliation)
    bankStatementFile: { bankId: string, content: string, fileName: string, rawFile?: File } | null;
    contributorFiles: { churchId: string; content: string; fileName: string; contributors?: Contributor[] }[];
    matchResults: MatchResult[];
    setMatchResults: React.Dispatch<React.SetStateAction<MatchResult[]>>;
    reportPreviewData: { income: GroupedReportData; expenses: GroupedReportData } | null;
    setReportPreviewData: React.Dispatch<React.SetStateAction<{ income: GroupedReportData; expenses: GroupedReportData } | null>>;
    comparisonType: ComparisonType;
    setComparisonType: React.Dispatch<React.SetStateAction<ComparisonType>>;
    hasActiveSession: boolean;
    setHasActiveSession: React.Dispatch<React.SetStateAction<boolean>>;
    isCompareDisabled: boolean;
    pendingTraining: any;
    setPendingTraining: (val: any) => void;
    activeReportId: string | null;
    setActiveReportId: React.Dispatch<React.SetStateAction<string | null>>;
    activeSpreadsheetData: SpreadsheetData | null; // NOVO: Dados da planilha ativa

    // Reconciliation Actions
    openLabManually: (targetFile?: { content: string, fileName: string, type: 'statement' | 'contributor', id: string, rawFile?: File }) => void;
    handleStatementUpload: (content: string, fileName: string, bankId: string, rawFile: File) => void;
    handleContributorsUpload: (content: string, fileName: string, churchId: string, rawFile?: File) => void;
    handleTrainingSuccess: (model: FileModel, data: Transaction[]) => void;
    removeBankStatementFile: () => void;
    removeContributorFile: (churchId: string) => void;
    handleCompare: () => void;
    handleBackToSettings: () => void;
    updateReportData: (updatedRow: MatchResult, reportType: 'income' | 'expenses', idToRemove?: string) => void;
    discardCurrentReport: () => void;
    resetReconciliation: () => void; 
    handleGmailSyncSuccess: (transactions: Transaction[]) => void; 

    // Manual Operations State & Handlers
    manualIdentificationTx: Transaction | null;
    setManualIdentificationTx: React.Dispatch<React.SetStateAction<Transaction | null>>;
    bulkIdentificationTxs: Transaction[] | null;
    setBulkIdentificationTxs: React.Dispatch<React.SetStateAction<Transaction[] | null>>;

    openManualIdentify: (transactionId: string) => void;
    openBulkManualIdentify: (transactions: Transaction[]) => void;
    closeManualIdentify: () => void;
    confirmManualIdentification: (transactionId: string, churchId: string) => void;
    confirmBulkManualIdentification: (transactionIds: string[], churchId: string) => void;

    manualMatchState: { record: MatchResult, suggestions: Transaction[] } | null;
    setManualMatchState: React.Dispatch<React.SetStateAction<{ record: MatchResult, suggestions: Transaction[] } | null>>;
    openManualMatchModal: (recordToMatch: MatchResult) => void;
    closeManualMatchModal: () => void;
    confirmManualAssociation: (selectedTx: Transaction) => void;

    // Smart Edit
    smartEditTarget: MatchResult | null;
    openSmartEdit: (match: MatchResult) => void;
    closeSmartEdit: () => void;
    saveSmartEdit: (updatedMatch: MatchResult) => void;

    divergenceConfirmation: MatchResult | null;
    setDivergenceConfirmation: React.Dispatch<React.SetStateAction<MatchResult | null>>;
    openDivergenceModal: (match: MatchResult) => void;
    closeDivergenceModal: () => void;
    confirmDivergence: (divergentMatch: MatchResult) => void;
    rejectDivergence: (divergentMatch: MatchResult) => void;

    learnAssociation: (matchResult: MatchResult) => Promise<void>;
    findMatchResult: (transactionId: string) => MatchResult | undefined;

    // AI
    loadingAiId: string | null;
    aiSuggestion: { id: string, name: string } | null;
    handleAnalyze: (transaction: Transaction, candidates: Contributor[]) => void;

    // Recompare Modal
    isRecompareModalOpen: boolean;
    openRecompareModal: () => void;
    closeRecompareModal: () => void;

    // Update Files Modal (NEW)
    isUpdateFilesModalOpen: boolean;
    openUpdateFilesModal: () => void;
    closeUpdateFilesModal: () => void;

    // Reports & Search (from useReportManager)
    savedReports: SavedReport[];
    maxSavedReports: number;
    searchFilters: SearchFilters;
    setSearchFilters: React.Dispatch<React.SetStateAction<SearchFilters>>;
    isSearchFiltersOpen: boolean;
    openSearchFilters: () => void;
    closeSearchFilters: () => void;
    clearSearchFilters: () => void;
    allHistoricalResults: MatchResult[];

    savingReportState: SavingReportState | null;
    openSaveReportModal: (state: SavingReportState) => void;
    closeSaveReportModal: () => void;
    confirmSaveReport: (name: string) => void;
    viewSavedReport: (reportId: string) => void;
    updateSavedReportName: (reportId: string, newName: string) => void;
    saveFilteredReport: (results: MatchResult[]) => void;
    saveCurrentReportChanges: () => void;
    overwriteSavedReport: (reportId: string, results: MatchResult[], spreadsheetData?: SpreadsheetData, silent?: boolean) => Promise<void>; 
    deleteOldReports: (dateThreshold: Date) => Promise<void>;
    isAutoSaving: boolean; // NOVO

    // Global
    deletingItem: DeletingItem | null;
    openDeleteConfirmation: (item: DeletingItem) => void;
    closeDeleteConfirmation: () => void;
    confirmDeletion: () => void;
    initialDataLoaded: boolean;
    isSyncing: boolean;
    summary: {
        autoConfirmed: { count: number; value: number; };
        manualConfirmed: { count: number; value: number; };
        pending: { count: number; value: number; };
        identifiedCount: number;
        unidentifiedCount: number;
        totalValue: number;
        valuePerChurch: [string, number][];
        isHistorical: boolean;
        methodBreakdown: Record<MatchMethod, number>;
    };
    isPaymentModalOpen: boolean;
    openPaymentModal: () => void;
    closePaymentModal: () => void;
}

export const AppContext = createContext<AppContextType>(null!);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user, systemSettings, incrementAiUsage } = useAuth();
    const { t } = useTranslation();
    const { showToast, setIsLoading, setActiveView } = useUI();

    const referenceData = useReferenceData(user, showToast);
    const reportManager = useReportManager(user, showToast);

    const effectiveIgnoreKeywords = useMemo(() => {
        return systemSettings.globalIgnoreKeywords || [];
    }, [systemSettings.globalIgnoreKeywords]);

    const reconciliation = useReconciliation({
        user, 
        churches: referenceData.churches,
        banks: referenceData.banks,
        fileModels: [],
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: effectiveIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast, setIsLoading, setActiveView
    });

    const [initialDataLoaded, setInitialDataLoaded] = useState(true);
    const [isSyncing, setIsSyncing] = useState(false); 

    const [deletingItem, setDeletingItem] = useState<DeletingItem | null>(null);
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const [isRecompareModalOpen, setIsRecompareModalOpen] = useState(false);
    const [isUpdateFilesModalOpen, setIsUpdateFilesModalOpen] = useState(false);

    const [smartEditTarget, setSmartEditTarget] = useState<MatchResult | null>(null);

    // Novo estado para planilha ativa
    const [activeSpreadsheetData, setActiveSpreadsheetData] = useState<SpreadsheetData | null>(null);

    // --- AUTO-SAVE EFFECT ---
    // Monitora mudanças em matchResults quando existe um relatório ativo e salva automaticamente
    useEffect(() => {
        if (!reconciliation.activeReportId || reconciliation.matchResults.length === 0) return;

        // Debounce aumentado para 5 segundos para reduzir a frequência de escritas
        const timer = setTimeout(() => {
            reportManager.overwriteSavedReport(
                reconciliation.activeReportId!, 
                reconciliation.matchResults, 
                undefined, 
                true // Silent mode
            );
        }, 5000);

        return () => clearTimeout(timer);
    }, [reconciliation.matchResults, reconciliation.activeReportId, reportManager.overwriteSavedReport]);

    const userSuffix = user ? `-${user.id}` : '-guest';
    const [summary, setSummary] = usePersistentState(`identificapix-dashboard-summary-v6${userSuffix}`, {
        autoConfirmed: { count: 0, value: 0 },
        manualConfirmed: { count: 0, value: 0 },
        pending: { count: 0, value: 0 },
        identifiedCount: 0, unidentifiedCount: 0, totalValue: 0, valuePerChurch: [], isHistorical: false,
        methodBreakdown: { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0, 'TEMPLATE': 0 }
    }, false);

    // Fetch de Dados (Background Sync) - NÃO BLOQUEANTE
    useEffect(() => {
        if (!user) return;
        const fetchData = async () => {
            setIsSyncing(true);
            try {
                const [churchesRes, banksRes, reportsRes] = await Promise.all([
                    supabase.from('churches').select('*').order('name'),
                    supabase.from('banks').select('*').order('name'),
                    supabase.from('saved_reports')
                        .select('id, name, created_at, record_count, user_id') 
                        .eq('user_id', user.id)
                        .order('created_at', { ascending: false }),
                ]);

                if (churchesRes.data) referenceData.setChurches(churchesRes.data as any);
                if (banksRes.data) referenceData.setBanks(banksRes.data as any);

                if (reportsRes.data) {
                    reportManager.setSavedReports((reportsRes.data || []).map(r => ({ 
                        id: r.id, 
                        name: r.name, 
                        createdAt: r.created_at, 
                        recordCount: r.record_count, 
                        user_id: r.user_id, 
                        data: null 
                    })));
                }
            } catch (err) { console.error('Background sync failed', err); } 
            finally { 
                setIsSyncing(false); 
                setInitialDataLoaded(true); 
            }
        };
        fetchData();
    }, [user?.id]);

    // Otimização: Dependemos apenas da referência do array matchResults
    // Removemos o cálculo pesado de hash (JSON.stringify) que estava travando a UI
    useEffect(() => {
        // Debounce curto para não recalcular a cada tecla
        const timer = setTimeout(() => {
            let resultsToProcess = reconciliation.matchResults;
            let isHistorical = false;

            if (resultsToProcess.length === 0 && reportManager.savedReports.length > 0) {
                // Evita carregar todos os dados históricos se não for necessário para o dashboard inicial
                // Apenas se realmente formos usar. Por enquanto, mantemos, mas com cuidado.
                // Idealmente, o dashboard usaria apenas metadados, mas a lógica atual exige processamento.
                resultsToProcess = reportManager.savedReports.flatMap(report => report.data?.results || []);
                isHistorical = true;
            }

            if (resultsToProcess.length === 0) return;

            const autoConfirmed = resultsToProcess.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'AUTOMATIC' || r.matchMethod === 'LEARNED' || !r.matchMethod));
            const manualConfirmed = resultsToProcess.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'MANUAL' || r.matchMethod === 'AI'));
            const pending = resultsToProcess.filter(r => r.status === 'NÃO IDENTIFICADO');

            const valuePerChurch = new Map<string, number>();
            const methodBreakdown: Record<MatchMethod, number> = { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0, 'TEMPLATE': 0 };

            // Loop único para performance
            let totalValue = 0;
            for (const r of resultsToProcess) {
                totalValue += r.transaction.amount;
                if (r.status === 'IDENTIFICADO') {
                    if (r.church && r.church.name !== '---' && r.transaction.amount > 0) {
                        const current = valuePerChurch.get(r.church.name) || 0;
                        valuePerChurch.set(r.church.name, current + r.transaction.amount);
                    }
                    const method = r.matchMethod || 'AUTOMATIC';
                    if (methodBreakdown[method] !== undefined) methodBreakdown[method]++;
                }
            }

            setSummary(prev => ({
                autoConfirmed: { count: autoConfirmed.length, value: autoConfirmed.reduce((sum, r) => sum + r.transaction.amount, 0) },
                manualConfirmed: { count: manualConfirmed.length, value: manualConfirmed.reduce((sum, r) => sum + r.transaction.amount, 0) },
                pending: { count: pending.length, value: pending.reduce((sum, r) => sum + r.transaction.amount, 0) },
                identifiedCount: autoConfirmed.length + manualConfirmed.length,
                unidentifiedCount: pending.length, 
                totalValue,
                valuePerChurch: Array.from(valuePerChurch.entries()).sort((a, b) => b[1] - a[1]),
                isHistorical, 
                methodBreakdown
            }));
        }, 800); // Aumentado debounce para 800ms
        return () => clearTimeout(timer);
    }, [reconciliation.matchResults, reportManager.savedReports.length]);

    const handleBackToSettings = useCallback(() => setActiveView('upload'), [setActiveView]);
    const openDeleteConfirmation = useCallback((item: DeletingItem) => setDeletingItem(item), []);
    const closeDeleteConfirmation = useCallback(() => setDeletingItem(null), []);

    // --- RESET FUNCTION UNIFIED ---
    const unifiedResetReconciliation = useCallback(() => {
        reconciliation.resetReconciliation();
        setActiveSpreadsheetData(null); // Limpa também a planilha ativa
    }, [reconciliation]);

    const confirmDeletion = useCallback(async () => {
        if (!deletingItem) return;
        if (deletingItem.type === 'report-row') {
             reconciliation.setReportPreviewData(prev => {
                 if (!prev) return null;
                 const newPreview = { ...prev };
                 const targetGroup = deletingItem.meta?.reportType === 'expenses' ? newPreview.expenses : newPreview.income;
                 Object.keys(targetGroup).forEach(key => { targetGroup[key] = targetGroup[key].filter(r => r.transaction.id !== deletingItem.id); });
                 return newPreview;
             });
             reconciliation.setMatchResults(prev => prev.filter(r => r.transaction.id !== deletingItem.id));
        } else if (deletingItem.type === 'report-group') {
             reconciliation.setReportPreviewData(prev => {
                 if (!prev) return null;
                 const newPreview = { ...prev };
                 const targetGroup = deletingItem.meta?.reportType === 'expenses' ? newPreview.expenses : newPreview.income;
                 if (targetGroup[deletingItem.id]) {
                     const idsToRemove = targetGroup[deletingItem.id].map(r => r.transaction.id);
                     delete targetGroup[deletingItem.id];
                     reconciliation.setMatchResults(prev => prev.filter(r => !idsToRemove.includes(r.transaction.id)));
                 }
                 return newPreview;
             });
        } else if (deletingItem.type === 'bank') {
            referenceData.setBanks(prev => prev.filter(b => b.id !== deletingItem.id));
            await supabase.from('banks').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'church') {
            referenceData.setChurches(prev => prev.filter(c => c.id !== deletingItem.id));
            await supabase.from('churches').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'report-saved') {
            reportManager.setSavedReports(prev => prev.filter(r => r.id !== deletingItem.id));
            await supabase.from('saved_reports').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'uploaded-files') { reconciliation.removeBankStatementFile(); }
        closeDeleteConfirmation();
        showToast("Ação realizada com sucesso.");
    }, [deletingItem, user, referenceData, reportManager, reconciliation, showToast, closeDeleteConfirmation]);

    const viewSavedReport = useCallback(async (reportId: string) => {
        setIsLoading(true);
        try {
            let report = reportManager.savedReports.find(r => r.id === reportId);
            if (!report) return;

            // LAZY LOAD LOGIC
            if (!report.data) {
                const { data: reportContent, error } = await supabase
                    .from('saved_reports')
                    .select('data')
                    .eq('id', reportId)
                    .single();

                if (error) throw error;

                if (reportContent) {
                    const parsedData = typeof reportContent.data === 'string' 
                        ? JSON.parse(reportContent.data) 
                        : reportContent.data;

                    report = { ...report, data: parsedData };
                    // Atualiza cache local
                    reportManager.setSavedReports(prev => prev.map(r => r.id === reportId ? report! : r));
                }
            }

            if (!report.data) throw new Error("Conteúdo do relatório vazio.");

            // Resetar estados antes de carregar novo relatório
            reconciliation.clearFiles();
            setActiveSpreadsheetData(null);

            // --- BRANCH DE DECISÃO: PLANILHA OU CONCILIAÇÃO ---
            if (report.data.spreadsheet) {
                // Carrega Planilha
                setActiveSpreadsheetData(report.data.spreadsheet);
                reconciliation.setActiveReportId(reportId);
                setActiveView('smart_analysis');
                showToast(`Planilha "${report.name}" carregada.`, "success");
            } else {
                // Carrega Conciliação Padrão
                const validResults = report.data.results.map((r: any) => ({ ...r, church: r.church || PLACEHOLDER_CHURCH }));
                reconciliation.setMatchResults(validResults);
                reconciliation.setReportPreviewData({
                    income: groupResultsByChurch(validResults.filter((r: any) => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                    expenses: { 'all_expenses_group': validResults.filter((r: any) => r.transaction.amount < 0) }
                });
                reconciliation.setHasActiveSession(true); 
                reconciliation.setActiveReportId(reportId); 
                setActiveView('reports'); 
                showToast(`Relatório "${report.name}" carregado.`, "success");
            }

        } catch (error: any) {
            console.error(error);
            showToast("Erro ao abrir relatório: " + error.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [reportManager.savedReports, reconciliation, setActiveView, setIsLoading, showToast]);

    // Nova função para salvar as alterações do relatório ativo
    const saveCurrentReportChanges = useCallback(() => {
        const reportId = reconciliation.activeReportId;
        if (!reportId) {
            showToast("Nenhum relatório salvo ativo para atualizar.", "error");
            return;
        }
        reportManager.overwriteSavedReport(reportId, reconciliation.matchResults);
    }, [reconciliation.activeReportId, reconciliation.matchResults, reportManager, showToast]);

    const findMatchResult = useCallback((transactionId: string) => reconciliation.matchResults.find(r => r.transaction.id === transactionId) || reportManager.allHistoricalResults.find(r => r.transaction.id === transactionId), [reconciliation.matchResults, reportManager.allHistoricalResults]);

    const openManualIdentify = useCallback((transactionId: string) => {
        const result = findMatchResult(transactionId);
        if (result) reconciliation.setManualIdentificationTx(result.transaction);
    }, [findMatchResult, reconciliation]);

    const openBulkManualIdentify = useCallback((transactions: Transaction[]) => { reconciliation.setBulkIdentificationTxs(transactions); }, [reconciliation]);

    const confirmManualIdentification = useCallback((transactionId: string, churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        const result = findMatchResult(transactionId);
        if (church && result) {
            const updated: MatchResult = { ...result, status: 'IDENTIFICADO', church, contributor: { id: `manual-${transactionId}`, name: result.transaction.cleanedDescription || result.transaction.description, amount: result.transaction.amount }, matchMethod: 'MANUAL', similarity: 100, contributorAmount: result.transaction.amount };
            if (reconciliation.matchResults.some(r => r.transaction.id === transactionId)) reconciliation.updateReportData(updated, 'income');
            else reportManager.updateSavedReportTransaction(transactionId, updated);
            reconciliation.closeManualIdentify(); 
            showToast('Identificação realizada.', 'success');
        }
    }, [referenceData.churches, findMatchResult, reconciliation, reportManager, showToast]);

    const confirmBulkManualIdentification = useCallback((transactionIds: string[], churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        transactionIds.forEach(id => {
            const result = findMatchResult(id);
            if (result) {
                const updated: MatchResult = { 
                    ...result, 
                    status: 'IDENTIFICADO', 
                    church, 
                    contributor: { id: `manual-${id}`, name: result.transaction.cleanedDescription || result.transaction.description, amount: result.transaction.amount }, 
                    matchMethod: 'MANUAL', 
                    similarity: 100, 
                    contributorAmount: result.transaction.amount 
                };
                if (reconciliation.matchResults.some(r => r.transaction.id === id)) reconciliation.updateReportData(updated, 'income');
                else reportManager.updateSavedReportTransaction(id, updated);
            }
        });
        reconciliation.closeManualIdentify();
        showToast(`${transactionIds.length} transações identificadas.`, 'success');
    }, [referenceData.churches, findMatchResult, reconciliation, reportManager, showToast]);

    const openSmartEdit = useCallback((match: MatchResult) => {
        setSmartEditTarget(match);
    }, []);

    const closeSmartEdit = useCallback(() => {
        setSmartEditTarget(null);
        reconciliation.setAiSuggestion(null);
    }, [reconciliation]);

    const saveSmartEdit = useCallback((updatedMatch: MatchResult) => {
        if (reconciliation.matchResults.some(r => r.transaction.id === updatedMatch.transaction.id)) {
            const ghostId = smartEditTarget?.status === 'PENDENTE' ? smartEditTarget.transaction.id : undefined;
            reconciliation.updateReportData(updatedMatch, 'income', ghostId);
        } else {
            reportManager.updateSavedReportTransaction(updatedMatch.transaction.id, updatedMatch);
        }
        showToast("Edição aplicada na tabela.", "success");
        setSmartEditTarget(null);
        reconciliation.setAiSuggestion(null);
    }, [reconciliation, reportManager, showToast, smartEditTarget]);

    const handleAnalyze = useCallback(async (transaction: Transaction, candidates: Contributor[]) => {
        reconciliation.setLoadingAiId(transaction.id);
        try {
            const candidateNames = candidates.slice(0, 50).map(c => c.name);
            const response = await fetch('/api/ai/suggestion', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    transactionDescription: transaction.description,
                    contributorNames: candidateNames
                })
            });

            if (!response.ok) throw new Error('Falha na API de IA');
            const data = await response.json();
            const suggestionText = data.text;

            if (suggestionText && !suggestionText.includes("Nenhuma sugestão clara")) {
                reconciliation.setAiSuggestion({ id: transaction.id, name: suggestionText });
                incrementAiUsage(); 
            } else {
                reconciliation.setAiSuggestion(null);
            }
        } catch (error) {
            console.error("Erro na análise IA:", error);
            showToast("Não foi possível obter sugestão da IA.", "error");
        } finally {
            reconciliation.setLoadingAiId(null);
        }
    }, [incrementAiUsage, showToast, reconciliation]);

    // --- NOVA FUNÇÃO GMAIL SYNC ---
    const handleGmailSyncSuccess = useCallback((transactions: Transaction[]) => {
        if (transactions.length === 0) return;

        const virtualFileName = `Importação Gmail - ${new Date().toLocaleDateString()}`;

        reconciliation.setBankStatementFile(prev => {
            const existingTxs = prev?.processedTransactions || [];
            const newTxs = transactions.filter(nt => !existingTxs.some(et => et.id === nt.id || (et.amount === nt.amount && et.date === nt.date && et.description === nt.description)));
            const merged = [...existingTxs, ...newTxs];

            return {
                bankId: prev?.bankId || 'gmail-bank',
                content: prev?.content || 'GMAIL_VIRTUAL_CONTENT',
                fileName: prev?.fileName || virtualFileName,
                processedTransactions: merged
            };
        });

        showToast(`${transactions.length} transações do Gmail importadas com sucesso!`, 'success');

    }, [reconciliation, showToast]);

    const value = useMemo(() => ({
        ...referenceData, ...reconciliation, isCompareDisabled: !reconciliation.bankStatementFile,
        effectiveIgnoreKeywords, 
        openManualIdentify, openBulkManualIdentify, confirmManualIdentification, confirmBulkManualIdentification, findMatchResult,
        ...reportManager, viewSavedReport, handleBackToSettings, deletingItem, openDeleteConfirmation,
        closeDeleteConfirmation, confirmDeletion, initialDataLoaded, isSyncing, summary, isPaymentModalOpen,
        openPaymentModal: () => setIsPaymentModalOpen(true), closePaymentModal: () => setIsPaymentModalOpen(false),
        isRecompareModalOpen, openRecompareModal: () => setIsRecompareModalOpen(true), closeRecompareModal: () => setIsRecompareModalOpen(false),
        smartEditTarget, openSmartEdit, closeSmartEdit, saveSmartEdit, handleAnalyze,
        saveCurrentReportChanges,
        handleGmailSyncSuccess,
        resetReconciliation: unifiedResetReconciliation,
        activeSpreadsheetData,
        isUpdateFilesModalOpen, 
        openUpdateFilesModal: () => setIsUpdateFilesModalOpen(true), 
        closeUpdateFilesModal: () => setIsUpdateFilesModalOpen(false)
    }), [referenceData, reconciliation, effectiveIgnoreKeywords, reportManager, viewSavedReport, handleBackToSettings, deletingItem, openDeleteConfirmation, closeDeleteConfirmation, confirmDeletion, initialDataLoaded, isSyncing, summary, isPaymentModalOpen, isRecompareModalOpen, openManualIdentify, openBulkManualIdentify, confirmManualIdentification, confirmBulkManualIdentification, findMatchResult, smartEditTarget, openSmartEdit, closeSmartEdit, saveSmartEdit, handleAnalyze, saveCurrentReportChanges, handleGmailSyncSuccess, unifiedResetReconciliation, activeSpreadsheetData, isUpdateFilesModalOpen]);

    return <AppContext.Provider value={value}>{children}<RecompareModal /></AppContext.Provider>;
};

import { useState, useCallback, useMemo } from 'react';
import { supabase } from '../services/supabaseClient';
import { usePersistentState } from './usePersistentState';
import { SavedReport, SearchFilters, SavingReportState, MatchResult, SpreadsheetData } from '../types';
import { User } from '@supabase/supabase-js';

const DEFAULT_SEARCH_FILTERS: SearchFilters = {
    dateRange: { start: null, end: null },
    valueFilter: { operator: 'any', value1: null, value2: null },
    transactionType: 'all',
    reconciliationStatus: 'all',
    filterBy: 'none',
    churchIds: [],
    contributorName: '',
    reportId: null,
};

// LIMITE DE SEGURANÇA (Hard Limit)
// Ajustado para 60 relatórios (Equivalente a 5 anos de histórico mensal).
const MAX_REPORTS_PER_USER = 60;

export const useReportManager = (user: User | null, showToast: (msg: string, type: 'success' | 'error') => void) => {

    // --- User Scoping for Local Storage ---
    const userSuffix = user ? `-${user.id}` : '-guest';

    const [savedReports, setSavedReports] = useState<SavedReport[]>([]);
    const [searchFilters, setSearchFilters] = usePersistentState<SearchFilters>(`identificapix-search-filters${userSuffix}`, DEFAULT_SEARCH_FILTERS);

    const [isSearchFiltersOpen, setIsSearchFiltersOpen] = useState(false);
    const [savingReportState, setSavingReportState] = useState<SavingReportState | null>(null);
    const [isAutoSaving, setIsAutoSaving] = useState(false);

    // --- Search Filters Actions ---
    const openSearchFilters = useCallback(() => setIsSearchFiltersOpen(true), []);
    const closeSearchFilters = useCallback(() => setIsSearchFiltersOpen(false), []);
    const clearSearchFilters = useCallback(() => setSearchFilters(DEFAULT_SEARCH_FILTERS), [setSearchFilters]);

    // --- Saved Reports Actions ---
    const updateSavedReportName = useCallback(async (reportId: string, newName: string) => {
        if(!user) return;
        setSavedReports(prev => prev.map(r => r.id === reportId ? { ...r, name: newName } : r));
        const { error } = await supabase.from('saved_reports').update({ name: newName }).eq('id', reportId);
        if (error) showToast('Erro ao renomear relatório.', 'error');
        else showToast('Relatório renomeado.', 'success');
    }, [user, showToast]);

    const updateSavedReportTransaction = useCallback(async (transactionId: string, updatedRow: MatchResult) => {
        if (!user) return;

        // Find the report containing the transaction
        const reportIndex = savedReports.findIndex(r => r.data?.results.some(res => res.transaction.id === transactionId));

        if (reportIndex === -1) return;

        const report = savedReports[reportIndex];
        if (!report.data) return;

        // Create updated results array
        const updatedResults = report.data.results.map(res => 
            res.transaction.id === transactionId ? updatedRow : res
        );

        // Update Local State
        const updatedReport = {
            ...report,
            data: {
                ...report.data,
                results: updatedResults
            }
        };

        setSavedReports(prev => {
            const newReports = [...prev];
            newReports[reportIndex] = updatedReport;
            return newReports;
        });

        // Update Supabase
        const { error } = await supabase
            .from('saved_reports')
            .update({ data: updatedReport.data as any }) // Cast to any to satisfy Json type
            .eq('id', report.id);

        if (error) {
            showToast('Erro ao atualizar relatório salvo.', 'error');
        } else {
            showToast('Relatório salvo atualizado.', 'success');
        }
    }, [user, savedReports, setSavedReports, showToast]);

    // NOVO: Sobrescreve um relatório inteiro (usado para salvar alterações da sessão)
    // Agora aceita spreadsheetData opcional para atualizar planilhas
    const overwriteSavedReport = useCallback(async (reportId: string, results: MatchResult[], spreadsheetData?: SpreadsheetData, silent: boolean = false) => {
        if (!user) return;

        const reportIndex = savedReports.findIndex(r => r.id === reportId);
        if (reportIndex === -1) return;

        if (silent) setIsAutoSaving(true);

        const report = savedReports[reportIndex];

        // Determina a contagem de registros (planilha vs conciliação)
        const recordCount = spreadsheetData?.rows ? spreadsheetData.rows.length : results.length;

        const updatedData = {
            results: results,
            sourceFiles: [], // Mantém limpo ou preserva se necessário (simplificado)
            bankStatementFile: null,
            spreadsheet: spreadsheetData || report.data?.spreadsheet
        };

        // PERFORMANCE: Apenas atualizamos o estado local (lista de relatórios) com metadados básicos
        // para evitar clonagem pesada de dados na lista principal.
        // O `data` no `savedReports` é opcional ou lazy loaded.
        setSavedReports(prev => {
            const newReports = [...prev];
            // Atualiza apenas metadados e mantém data (se já carregado) ou atualiza
            newReports[reportIndex] = {
                ...prev[reportIndex],
                recordCount: recordCount,
                data: updatedData // Mantemos sync para consistência, mas o AppContext que manda.
            };
            return newReports;
        });

        // OPTIMISTIC UI: Feedback Imediato se não for silencioso
        if (!silent) showToast('Alterações salvas com sucesso!', 'success');

        // Update Supabase (Background)
        const { error } = await supabase
            .from('saved_reports')
            .update({ 
                data: updatedData as any,
                record_count: recordCount 
            })
            .eq('id', reportId);

        if (silent) setIsAutoSaving(false);

        if (error) {
            console.error("Erro ao persistir:", error);
            if (!silent) showToast('Aviso: Falha ao sincronizar com a nuvem. Verifique sua conexão.', 'error');
        }
    }, [user, savedReports, setSavedReports, showToast]);

    const saveFilteredReport = useCallback((results: MatchResult[]) => {
        setSavingReportState({
            type: 'search',
            results: results,
            groupName: 'Filtrado'
        });
    }, []);

    const openSaveReportModal = useCallback((state: SavingReportState) => setSavingReportState(state), []);
    const closeSaveReportModal = useCallback(() => setSavingReportState(null), []);

    const confirmSaveReport = useCallback(async (name: string) => {
        if (!savingReportState || !user) return;

        // CHECK DE LIMITE DE ARMAZENAMENTO
        if (savedReports.length >= MAX_REPORTS_PER_USER) {
            showToast(`Limite de ${MAX_REPORTS_PER_USER} relatórios atingido. Exclua alguns antigos para salvar novos.`, 'error');
            closeSaveReportModal();
            return;
        }

        const isSpreadsheet = savingReportState.type === 'spreadsheet';
        const recordCount = isSpreadsheet && savingReportState.spreadsheetData?.rows
            ? savingReportState.spreadsheetData.rows.length 
            : savingReportState.results.length;

        const newReport: SavedReport = {
            id: `rep-${Date.now()}`,
            name: name,
            createdAt: new Date().toISOString(),
            recordCount: recordCount,
            user_id: user.id,
            data: {
                results: savingReportState.results,
                sourceFiles: [],
                bankStatementFile: null,
                spreadsheet: isSpreadsheet ? savingReportState.spreadsheetData : undefined
            }
        };

        setSavedReports(prev => [newReport, ...prev]);
        closeSaveReportModal();

        const { error } = await supabase.from('saved_reports').insert({
            id: newReport.id,
            name: newReport.name,
            record_count: newReport.recordCount,
            user_id: newReport.user_id,
            data: newReport.data as any
        });

        if (error) {
            setSavedReports(prev => prev.filter(r => r.id !== newReport.id));
            showToast('Erro ao salvar relatório no banco de dados.', 'error');
        } else {
            showToast('Relatório salvo com sucesso!', 'success');
        }
    }, [savingReportState, user, showToast, closeSaveReportModal, savedReports.length]);

    // Função para deletar relatórios antigos em massa
    const deleteOldReports = useCallback(async (dateThreshold: Date) => {
        if (!user) return;

        const reportsToDelete = savedReports.filter(r => new Date(r.createdAt) < dateThreshold);
        if (reportsToDelete.length === 0) {
            showToast("Nenhum relatório encontrado anterior a esta data.", "error");
            return;
        }

        // Optimistic UI Update
        setSavedReports(prev => prev.filter(r => new Date(r.createdAt) >= dateThreshold));

        const { error } = await supabase
            .from('saved_reports')
            .delete()
            .lt('created_at', dateThreshold.toISOString())
            .eq('user_id', user.id);

        if (error) {
            // Revert state (complex, requires refetching usually, but simplified here)
            showToast("Erro ao excluir relatórios no servidor.", "error");
        } else {
            showToast(`${reportsToDelete.length} relatórios antigos foram excluídos.`, "success");
        }
    }, [user, savedReports, showToast]);

    const allHistoricalResults = useMemo(() => {
        return savedReports
            .filter(r => r.data && r.data.results)
            .flatMap(report => report.data!.results);
    }, [savedReports]);

    return useMemo(() => ({
        savedReports, setSavedReports,
        maxSavedReports: MAX_REPORTS_PER_USER, // EXPOSED CONSTANT
        searchFilters, setSearchFilters,
        isSearchFiltersOpen, openSearchFilters, closeSearchFilters, clearSearchFilters,
        savingReportState, openSaveReportModal, closeSaveReportModal, confirmSaveReport,
        updateSavedReportName, updateSavedReportTransaction, saveFilteredReport, overwriteSavedReport,
        deleteOldReports,
        allHistoricalResults,
        isAutoSaving
    }), [
        savedReports, searchFilters, isSearchFiltersOpen, savingReportState, allHistoricalResults, isAutoSaving,
        setSavedReports, setSearchFilters, openSearchFilters, closeSearchFilters, clearSearchFilters,
        openSaveReportModal, closeSaveReportModal, confirmSaveReport, updateSavedReportName, updateSavedReportTransaction, saveFilteredReport, overwriteSavedReport,
        deleteOldReports
    ]);
};

import React, { useContext, useState, useMemo, useEffect, useCallback } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useUI } from '../contexts/UIContext';
import { useTranslation } from '../contexts/I18nContext';
import { EmptyState } from '../components/EmptyState';
import { EditableReportTable } from '../components/reports/EditableReportTable';
import { 
    ChartBarIcon, 
    BuildingOfficeIcon, 
    ExclamationTriangleIcon, 
    BanknotesIcon, 
    FloppyDiskIcon, 
    DocumentDuplicateIcon,
    MagnifyingGlassIcon,
    ChevronLeftIcon,
    ChevronRightIcon,
    PrinterIcon,
    DocumentArrowDownIcon,
    FolderPlusIcon,
    CheckCircleIcon,
    ArrowPathIcon
} from '../components/Icons';
import { formatCurrency, formatDate } from '../utils/formatters';
import { MatchResult } from '../types';

interface ChurchSummaryItem {
    id: string;
    name: string;
    count: number;
    total: number;
}

// Extracted ChurchChip component to avoid type errors and improve performance
const ChurchChip = ({ item, isSelected, onClick }: { item: ChurchSummaryItem, isSelected: boolean, onClick: () => void }) => {
    return (
        <button
            onClick={onClick}
            className={`
                flex-shrink-0 flex items-center gap-2 px-3 py-1 rounded-full border transition-all duration-200 text-xs
                ${isSelected 
                    ? 'bg-gradient-to-r from-blue-50 to-indigo-50 border-blue-200 text-blue-700 shadow-sm ring-1 ring-blue-100 dark:from-blue-900/40 dark:to-indigo-900/40 dark:border-blue-800 dark:text-blue-300' 
                    : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 hover:border-blue-300 dark:hover:border-slate-500'
                }
            `}
        >
            {isSelected && <div className="w-1.5 h-1.5 rounded-full bg-blue-600 shadow-[0_0_5px_rgba(37,99,235,0.6)]"></div>}
            <span className="font-bold truncate max-w-[150px]">{item.name}</span>
            <span className={`px-1.5 rounded text-[10px] font-bold ${isSelected ? 'bg-white/50 dark:bg-black/20' : 'bg-slate-100 text-slate-500 dark:bg-slate-700 dark:text-slate-400'}`}>
                {item.count}
            </span>
        </button>
    );
};

// Extracted CategoryPill component
const CategoryPill = ({ id, label, count, icon: Icon, isActive, onClick }: any) => {
    let activeClass = "";
    let iconClass = "";

    if (id === 'churches') {
        activeClass = "bg-gradient-to-r from-blue-600 to-indigo-600 text-white shadow-md shadow-blue-500/30";
        iconClass = isActive ? "text-white" : "text-blue-500";
    } else if (id === 'unidentified') {
        activeClass = "bg-gradient-to-r from-amber-500 to-orange-500 text-white shadow-md shadow-orange-500/30";
        iconClass = isActive ? "text-white" : "text-amber-500";
    } else {
        activeClass = "bg-gradient-to-r from-rose-500 to-red-600 text-white shadow-md shadow-red-500/30";
        iconClass = isActive ? "text-white" : "text-rose-500";
    }

    const baseClass = "bg-white dark:bg-slate-800 text-slate-500 dark:text-slate-400 border border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-700";

    return (
        <button
            onClick={onClick}
            className={`
                relative flex items-center gap-2 px-3 py-1.5 rounded-full transition-all duration-300 text-[10px] font-bold uppercase tracking-wide
                ${isActive ? `${activeClass} transform scale-105 z-10 border-transparent` : baseClass}
            `}
        >
            <Icon className={`w-3.5 h-3.5 ${iconClass}`} />
            <span>{label}</span>
            <span className={`px-1.5 py-0.5 rounded-md text-[9px] leading-none ${isActive ? 'bg-white/20 text-white' : 'bg-slate-100 dark:bg-slate-900 text-slate-500'}`}>
                {count}
            </span>
        </button>
    );
};

export const ReportsView: React.FC = () => {
    const { 
        reportPreviewData, 
        activeReportId, 
        openSaveReportModal, 
        matchResults,
        updateReportData,
        loadingAiId,
        openSmartEdit,
        openUpdateFilesModal,
        isAutoSaving // NOVO
    } = useContext(AppContext);

    const { setActiveView } = useUI();
    const { t, language } = useTranslation();

    // Categorias Principais
    const [activeCategory, setActiveCategory] = useState<'churches' | 'unidentified' | 'expenses'>('churches');

    // ID do Relatório Específico Selecionado (Ex: ID da Igreja)
    const [selectedReportId, setSelectedReportId] = useState<string | null>(null);

    const [sortConfig, setSortConfig] = useState<{ key: string, direction: 'asc' | 'desc' } | null>(null);
    const [searchTerm, setSearchTerm] = useState('');

    // --- EFEITO: Seleção Inicial Automática ---
    useEffect(() => {
        if (!reportPreviewData) return;

        if (activeCategory === 'churches') {
            const churchIds = Object.keys(reportPreviewData.income).filter(k => k !== 'unidentified').sort();
            if (churchIds.length > 0) {
                // Se o ID selecionado não estiver na lista de igrejas, seleciona o primeiro
                if (!selectedReportId || !churchIds.includes(selectedReportId)) {
                    setSelectedReportId(churchIds[0]);
                }
            } else {
                setSelectedReportId(null);
            }
        } else if (activeCategory === 'unidentified') {
            setSelectedReportId('unidentified');
        } else if (activeCategory === 'expenses') {
            setSelectedReportId('all_expenses_group');
        }
    }, [activeCategory, reportPreviewData]);

    // --- DADOS CALCULADOS ---
    const churchList = useMemo((): ChurchSummaryItem[] => {
        if (!reportPreviewData?.income) return [];
        return Object.entries(reportPreviewData.income)
            .filter(([id]) => id !== 'unidentified')
            .map(([id, results]) => {
                const res = results as MatchResult[];
                return {
                    id,
                    name: res[0]?.church?.name || 'Igreja Desconhecida',
                    count: res.length,
                    total: res.reduce((sum, r) => sum + r.transaction.amount, 0)
                };
            })
            .sort((a, b) => a.name.localeCompare(b.name));
    }, [reportPreviewData]);

    const counts = useMemo(() => {
        const churches = churchList.length;
        const pending = reportPreviewData?.income['unidentified']?.length || 0;
        const expenses = reportPreviewData?.expenses['all_expenses_group']?.length || 0;
        return { churches, pending, expenses };
    }, [churchList, reportPreviewData]);

    // Dados da Tabela Ativa
    const activeData = useMemo(() => {
        if (!reportPreviewData || !selectedReportId) return [];

        let data: MatchResult[] = [];
        if (activeCategory === 'expenses') {
            data = reportPreviewData.expenses[selectedReportId] || [];
        } else {
            data = reportPreviewData.income[selectedReportId] || [];
        }

        // Filtragem local por termo de busca
        if (searchTerm) {
            const lower = searchTerm.toLowerCase();
            data = data.filter(r => 
                (r.transaction.description || '').toLowerCase().includes(lower) ||
                (r.contributor?.name || '').toLowerCase().includes(lower) ||
                (r.contributor?.cleanedName || '').toLowerCase().includes(lower)
            );
        }

        return data;
    }, [reportPreviewData, selectedReportId, activeCategory, searchTerm]);

    const activeReportType = activeCategory === 'expenses' ? 'expenses' : 'income';

    // Totais do Relatório Ativo
    const activeSummary = useMemo(() => {
        const count = activeData.length;
        const total = activeData.reduce((sum, r) => sum + r.transaction.amount, 0);

        // Filtros
        const pendingTxs = activeData.filter(r => r.status === 'PENDENTE');
        const autoTxs = activeData.filter(r => r.status === 'IDENTIFICADO' && r.matchMethod !== 'MANUAL');
        const manualTxs = activeData.filter(r => r.status === 'IDENTIFICADO' && r.matchMethod === 'MANUAL');

        // Contagens e Valores
        const pending = pendingTxs.length;
        const pendingValue = pendingTxs.reduce((sum, r) => sum + (r.contributorAmount || 0), 0);

        const auto = autoTxs.length;
        const autoValue = autoTxs.reduce((sum, r) => sum + r.transaction.amount, 0);

        const manual = manualTxs.length;
        const manualValue = manualTxs.reduce((sum, r) => sum + r.transaction.amount, 0);

        return { 
            count, total, 
            pending, pendingValue, 
            auto, autoValue, 
            manual, manualValue 
        };
    }, [activeData]);

    const handleSort = (key: string) => {
        setSortConfig(current => ({
            key,
            direction: current?.key === key && current.direction === 'asc' ? 'desc' : 'asc'
        }));
    };

    const sortedData = useMemo(() => {
        if (!sortConfig) return activeData;
        return [...activeData].sort((a, b) => {
            let valA: any;
            let valB: any;

            if (sortConfig.key.includes('.')) {
                const parts = sortConfig.key.split('.');
                valA = parts.reduce((obj: any, k) => obj?.[k], a);
                valB = parts.reduce((obj: any, k) => obj?.[k], b);
            } else {
                valA = (a as any)[sortConfig.key];
                valB = (b as any)[sortConfig.key];
            }

            if (valA === undefined || valA === null) valA = '';
            if (valB === undefined || valB === null) valB = '';

            if (typeof valA === 'string') {
                valA = valA.toLowerCase();
                valB = valB.toLowerCase();
            }

            if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
            if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
            return 0;
        });
    }, [activeData, sortConfig]);

    const handleSaveReport = () => {
        const resultsToSave = matchResults;
        openSaveReportModal({
            type: 'global',
            results: resultsToSave,
            groupName: 'Geral'
        });
    };

    const handleDownload = () => {
        const headers = ["Data", "Descrição", "Tipo", "Status", "Valor"];
        const csvContent = [
            headers.join(";"),
            ...sortedData.map(r => {
                const date = formatDate(r.transaction.date);
                const desc = (r.contributor?.cleanedName || r.transaction.description).replace(/;/g, ' ');
                const type = (r.contributor?.contributionType || r.transaction.contributionType || "").replace(/;/g, ' ');
                const status = r.status === 'IDENTIFICADO' ? (r.matchMethod || 'AUTO') : r.status;
                // Formata para padrão brasileiro no CSV (vírgula decimal)
                const amount = (r.status === 'PENDENTE' ? (r.contributorAmount || 0) : r.transaction.amount)
                    .toFixed(2).replace('.', ',');

                return [`"${date}"`, `"${desc}"`, `"${type}"`, `"${status}"`, `"${amount}"`].join(";");
            })
        ].join("\n");

        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", `relatorio_${new Date().toISOString().slice(0,10)}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const handlePrint = () => {
        const printWindow = window.open('', '_blank');
        if (!printWindow) return;

        const title = activeCategory === 'churches' 
            ? (churchList.find(c => c.id === selectedReportId)?.name || 'Relatório de Igreja')
            : activeCategory === 'unidentified' ? 'Transações Pendentes' : 'Saídas e Despesas';

        const tableRows = sortedData.map(r => {
            const date = formatDate(r.transaction.date);
            const name = r.contributor?.cleanedName || r.contributor?.name || r.transaction.cleanedDescription || r.transaction.description;
            const amount = formatCurrency(r.status === 'PENDENTE' ? (r.contributorAmount || 0) : r.transaction.amount, language);
            const type = r.contributor?.contributionType || r.transaction.contributionType || '---';
            const status = r.status === 'IDENTIFICADO' ? (r.matchMethod || 'AUTO') : r.status;

            return `
                <tr>
                    <td>${date}</td>
                    <td>${name}</td>
                    <td style="text-align: center;">${type}</td>
                    <td style="text-align: center;">${status}</td>
                    <td style="text-align: right;">${amount}</td>
                </tr>
            `;
        }).join('');

        printWindow.document.write(`
            <html>
                <head>
                    <title>${title} - IdentificaPix</title>
                    <style>
                        body { font-family: 'Inter', sans-serif; padding: 20px; color: #1e293b; }
                        h1 { font-size: 20px; margin-bottom: 5px; text-transform: uppercase; }
                        p { margin: 0 0 20px 0; color: #64748b; font-size: 12px; }
                        .summary { display: flex; gap: 20px; margin-bottom: 20px; padding: 15px; background: #f8fafc; border-radius: 8px; border: 1px solid #e2e8f0; }
                        .summary-item { display: flex; flex-direction: column; }
                        .summary-label { font-size: 10px; font-weight: bold; text-transform: uppercase; color: #64748b; }
                        .summary-value { font-size: 14px; font-weight: bold; color: #0f172a; }
                        table { width: 100%; border-collapse: collapse; font-size: 11px; }
                        th { text-align: left; background: #f1f5f9; padding: 8px; border-bottom: 2px solid #cbd5e1; text-transform: uppercase; font-size: 10px; color: #475569; }
                        td { padding: 8px; border-bottom: 1px solid #e2e8f0; }
                        tr:nth-child(even) { background: #f8fafc; }
                    </style>
                </head>
                <body>
                    <h1>${title}</h1>
                    <p>Gerado em: ${new Date().toLocaleString()}</p>

                    <div class="summary">
                        <div class="summary-item">
                            <span class="summary-label">Quantidade</span>
                            <span class="summary-value">${activeSummary.count}</span>
                        </div>
                        <div class="summary-item">
                            <span class="summary-label">Total</span>
                            <span class="summary-value">${formatCurrency(activeSummary.total, language)}</span>
                        </div>
                    </div>

                    <table>
                        <thead>
                            <tr>
                                <th style="width: 15%">Data</th>
                                <th style="width: 45%">Nome / Descrição</th>
                                <th style="width: 15%; text-align: center;">Tipo</th>
                                <th style="width: 10%; text-align: center;">Status</th>
                                <th style="width: 15%; text-align: right;">Valor</th>
                            </tr>
                        </thead>
                        <tbody>
                            ${tableRows}
                        </tbody>
                    </table>
                    <script>
                        window.onload = function() { window.print(); }
                    </script>
                </body>
            </html>
        `);
        printWindow.document.close();
    };

    const handleRowChange = (updatedRow: MatchResult) => {
        updateReportData(updatedRow, activeReportType);
    };

    const handleEdit = (row: MatchResult) => {
        openSmartEdit(row);
    };

    if (!reportPreviewData) {
        return (
            <div className="flex-1 flex items-center justify-center">
                <EmptyState
                    icon={<ChartBarIcon className="w-12 h-12 text-brand-blue dark:text-blue-400" />}
                    title={t('empty.reports.title')}
                    message={t('empty.reports.message')}
                    action={{
                        text: t('empty.dashboard.saved.action'),
                        onClick: () => setActiveView('upload'),
                    }}
                />
            </div>
        );
    }

    return (
        <div className="flex flex-col h-full animate-fade-in gap-2 pb-2 px-1">

            {/* 1. TOP BAR COMPACTADA: Title & Controls */}
            <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-2 flex-shrink-0">
                <div className="flex items-center gap-4">
                    <h2 className="text-lg font-black text-brand-deep dark:text-white tracking-tight leading-none">{t('reports.title')}</h2>

                    {/* CATEGORY TABS (Compact) */}
                    <div className="flex items-center gap-2 bg-slate-100 dark:bg-slate-900/50 p-0.5 rounded-full border border-slate-200 dark:border-slate-800">
                        <CategoryPill 
                            id="churches" 
                            label="Igrejas" 
                            count={counts.churches} 
                            icon={BuildingOfficeIcon}
                            isActive={activeCategory === 'churches'}
                            onClick={() => setActiveCategory('churches')}
                        />
                        <CategoryPill 
                            id="unidentified" 
                            label="Pendentes" 
                            count={counts.pending} 
                            icon={ExclamationTriangleIcon}
                            isActive={activeCategory === 'unidentified'}
                            onClick={() => setActiveCategory('unidentified')}
                        />
                        <CategoryPill 
                            id="expenses" 
                            label="Saídas" 
                            count={counts.expenses} 
                            icon={BanknotesIcon}
                            isActive={activeCategory === 'expenses'}
                            onClick={() => setActiveCategory('expenses')}
                        />
                    </div>
                </div>

                {/* ACTIONS (RIGHT) - Separated buttons for clear function distinction */}
                <div className="flex items-center gap-2 w-full md:w-auto ml-auto">

                    {/* NEW BUTTON: Manage Source Files */}
                    <button 
                        onClick={openUpdateFilesModal}
                        className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-[10px] font-bold text-slate-600 dark:text-slate-300 hover:text-indigo-600 hover:border-indigo-200 transition-all shadow-sm hover:shadow-md active:scale-95"
                        title="Adicionar ou substituir arquivos"
                    >
                        <FolderPlusIcon className="w-3.5 h-3.5" />
                        <span>Gerenciar Arquivos</span>
                    </button>

                    <div className="w-px h-6 bg-slate-200 dark:bg-slate-700 mx-1"></div>

                    {/* Botões Discretos (Download & Print) */}
                    <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 rounded-full p-1 mr-2 border border-slate-200 dark:border-slate-700">
                        <button 
                            onClick={handleDownload}
                            className="p-1.5 rounded-full text-slate-400 hover:text-brand-blue hover:bg-white dark:hover:bg-slate-700 transition-all"
                            title="Baixar CSV"
                        >
                            <DocumentArrowDownIcon className="w-4 h-4" />
                        </button>
                        <div className="w-px h-3 bg-slate-300 dark:bg-slate-600"></div>
                        <button 
                            onClick={handlePrint}
                            className="p-1.5 rounded-full text-slate-400 hover:text-brand-blue hover:bg-white dark:hover:bg-slate-700 transition-all"
                            title="Imprimir"
                        >
                            <PrinterIcon className="w-4 h-4" />
                        </button>
                    </div>

                    {/* Auto-Save Indicator (Substitui o botão de salvar) */}
                    {activeReportId ? (
                        <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-bold border transition-all ${isAutoSaving ? 'bg-amber-50 text-amber-600 border-amber-200' : 'bg-emerald-50 text-emerald-600 border-emerald-200'}`}>
                            {isAutoSaving ? (
                                <>
                                    <ArrowPathIcon className="w-3 h-3 animate-spin" />
                                    <span>Salvando...</span>
                                </>
                            ) : (
                                <>
                                    <CheckCircleIcon className="w-3 h-3" />
                                    <span>Salvo</span>
                                </>
                            )}
                        </div>
                    ) : (
                        /* Botão Salvar Novo Relatório (Apenas se for novo) */
                        <button 
                            onClick={handleSaveReport}
                            className="relative flex items-center justify-center gap-2 px-6 py-2 rounded-full text-[10px] uppercase font-bold text-white bg-gradient-to-r from-emerald-600 to-teal-600 hover:from-emerald-700 hover:to-teal-700 shadow-lg shadow-emerald-500/30 hover:-translate-y-0.5 transition-all active:scale-95"
                        >
                            <DocumentDuplicateIcon className="w-3.5 h-3.5" />
                            <span>{t('reports.saveReport')}</span>
                        </button>
                    )}
                </div>
            </div>

            {/* 2. CHURCH SELECTOR (Ultra Compact Horizontal Scroll) */}
            {activeCategory === 'churches' && (
                <div className="w-full">
                    <div className="flex flex-nowrap items-center gap-2 overflow-x-auto custom-scrollbar pb-2 px-1 touch-pan-x">
                        {churchList.length > 0 ? (
                            churchList.map(item => (
                                <ChurchChip 
                                    key={item.id} 
                                    item={item} 
                                    isSelected={selectedReportId === item.id}
                                    onClick={() => setSelectedReportId(item.id)}
                                />
                            ))
                        ) : (
                            <span className="text-xs text-slate-400 italic px-2">Nenhuma igreja identificada.</span>
                        )}
                    </div>
                </div>
            )}

            {/* 3. REPORT CONTENT (Maximized Vertical Space) */}
            <div className="flex-1 bg-white dark:bg-slate-800 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-card overflow-hidden flex flex-col relative">

                {/* 3.1. Report Header / Stats Strip (Condensed) */}
                <div className="px-4 py-2 bg-slate-50/80 dark:bg-slate-900/50 border-b border-slate-100 dark:border-slate-700 flex flex-col md:flex-row md:items-center justify-between gap-2 shrink-0 backdrop-blur-sm">

                    <div className="flex items-center gap-3">
                        <div className={`p-1.5 rounded-lg ${activeCategory === 'unidentified' ? 'bg-amber-100 text-amber-600' : activeCategory === 'expenses' ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'}`}>
                            {activeCategory === 'unidentified' ? <ExclamationTriangleIcon className="w-4 h-4"/> : activeCategory === 'expenses' ? <BanknotesIcon className="w-4 h-4"/> : <BuildingOfficeIcon className="w-4 h-4"/>}
                        </div>
                        <div>
                            <h3 className="text-xs font-black text-slate-800 dark:text-white uppercase tracking-wide">
                                {activeCategory === 'churches' 
                                    ? churchList.find(c => c.id === selectedReportId)?.name || 'Selecione uma Igreja'
                                    : activeCategory === 'unidentified' ? 'Transações Pendentes' : 'Saídas e Despesas'
                                }
                            </h3>
                            <div className="flex items-center gap-2 text-[10px] font-bold text-slate-500 mt-0.5">
                                <span>Total: {activeSummary.count}</span>
                                <span className="w-px h-2 bg-slate-300"></span>
                                <span className={`${activeCategory === 'expenses' ? 'text-red-600' : 'text-emerald-600'}`}>
                                    {formatCurrency(activeSummary.total, language)}
                                </span>
                            </div>
                        </div>
                    </div>

                    {/* Stats Pills & Search (Compact) */}
                    <div className="flex items-center gap-2 overflow-x-auto no-scrollbar">
                        <div className="flex gap-2">
                            {/* AUTO PILL */}
                            <div className="flex items-center gap-2 px-2.5 py-1 bg-emerald-50 text-emerald-700 border border-emerald-100 rounded-lg">
                                <div className="flex flex-col leading-none">
                                    <span className="text-[8px] font-black uppercase tracking-wide opacity-70">Auto</span>
                                    <span className="text-[10px] font-bold">{activeSummary.auto}</span>
                                </div>
                                <span className="text-[10px] font-bold font-mono text-emerald-800 border-l border-emerald-200 pl-2">
                                    {formatCurrency(activeSummary.autoValue, language)}
                                </span>
                            </div>

                            {/* MANUAL PILL */}
                            <div className="flex items-center gap-2 px-2.5 py-1 bg-blue-50 text-blue-700 border border-blue-100 rounded-lg">
                                <div className="flex flex-col leading-none">
                                    <span className="text-[8px] font-black uppercase tracking-wide opacity-70">Manual</span>
                                    <span className="text-[10px] font-bold">{activeSummary.manual}</span>
                                </div>
                                <span className="text-[10px] font-bold font-mono text-blue-800 border-l border-blue-200 pl-2">
                                    {formatCurrency(activeSummary.manualValue, language)}
                                </span>
                            </div>

                            {/* PENDING PILL */}
                            {activeSummary.pending > 0 && (
                                <div className="flex items-center gap-2 px-2.5 py-1 bg-amber-50 text-amber-700 border border-amber-100 rounded-lg">
                                    <div className="flex flex-col leading-none">
                                        <span className="text-[8px] font-black uppercase tracking-wide opacity-70">Pend</span>
                                        <span className="text-[10px] font-bold">{activeSummary.pending}</span>
                                    </div>
                                    <span className="text-[10px] font-bold font-mono text-amber-800 border-l border-amber-200 pl-2">
                                        {formatCurrency(activeSummary.pendingValue, language)}
                                    </span>
                                </div>
                            )}
                        </div>

                        <div className="w-px h-6 bg-slate-200 dark:bg-slate-700 mx-1 hidden md:block"></div>

                        <div className="relative group">
                            <MagnifyingGlassIcon className="w-3 h-3 text-slate-400 absolute left-2 top-1/2 -translate-y-1/2 group-focus-within:text-brand-blue transition-colors" />
                            <input 
                                type="text" 
                                placeholder="Pesquisar..." 
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="pl-7 pr-2 py-1 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-600 rounded-lg text-[10px] font-medium focus:ring-1 focus:ring-brand-blue/30 focus:border-brand-blue outline-none w-24 focus:w-40 transition-all"
                            />
                        </div>
                    </div>
                </div>

                {/* 3.2. Table Area (Takes remaining space) */}
                <div className="flex-1 min-h-0 relative">
                    {sortedData.length > 0 ? (
                        <div className="absolute inset-0">
                            <EditableReportTable 
                                data={sortedData}
                                onRowChange={handleRowChange}
                                reportType={activeReportType}
                                sortConfig={sortConfig}
                                onSort={handleSort}
                                loadingAiId={loadingAiId}
                                onEdit={handleEdit}
                            />
                        </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-full text-slate-400">
                            <p className="text-xs italic">Nenhum dado encontrado para esta seleção.</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect, useRef } from 'react';
import { get, set } from 'idb-keyval';

export function usePersistentState<T>(key: string, initialValue: T, isHeavy: boolean = false): [T, React.Dispatch<React.SetStateAction<T>>] {
    const [state, setState] = useState<T>(() => {
        if (isHeavy) return initialValue;
        try {
            if (typeof window !== 'undefined') {
                const item = window.localStorage.getItem(key);
                return item ? JSON.parse(item) : initialValue;
            }
        } catch (error) {
            console.warn(`Erro ao ler ${key} do localStorage:`, error);
        }
        return initialValue;
    });

    const isHydrated = useRef(false);
    const isMounted = useRef(false);
    const timeoutRef = useRef<any>(null);
    const lastSavedValue = useRef<string>('');

    useEffect(() => {
        isMounted.current = true;

        const hydrate = async () => {
            if (!isHeavy) {
                isHydrated.current = true;
                return;
            }

            try {
                const idbPromise = get(key);
                const timeoutPromise = new Promise((_, reject) => setTimeout(() => reject("timeout"), 2500));
                const value = await Promise.race([idbPromise, timeoutPromise]) as T | undefined;

                if (isMounted.current && value !== undefined && value !== null) {
                    setState(value);
                    lastSavedValue.current = JSON.stringify(value);
                }
            } catch (error) {
                console.warn(`Erro hidratação ${key}:`, error);
            } finally {
                if (isMounted.current) isHydrated.current = true;
            }
        };

        hydrate();
        return () => { isMounted.current = false; };
    }, [key, isHeavy]);

    useEffect(() => {
        if (!isHydrated.current || !isMounted.current) return;

        if (timeoutRef.current) clearTimeout(timeoutRef.current);

        // Otimização: Aumenta o delay para dados pesados (2s) vs leves (500ms)
        const delay = isHeavy ? 2000 : 500;

        timeoutRef.current = setTimeout(() => {
            // Executa em idle para não bloquear a UI
            const performSave = async () => {
                try {
                    const serialized = JSON.stringify(state);
                    // Evita escritas desnecessárias se o dado não mudou
                    if (serialized === lastSavedValue.current) return;

                    if (isHeavy) {
                        await set(key, state);
                    } else {
                        window.localStorage.setItem(key, serialized);
                    }
                    lastSavedValue.current = serialized;
                } catch (error) {
                    console.error(`Erro salvamento ${key}:`, error);
                }
            };

            // Fallback para requestIdleCallback
            if (typeof window !== 'undefined' && (window as any).requestIdleCallback) {
                (window as any).requestIdleCallback(performSave, { timeout: 1000 });
            } else {
                setTimeout(performSave, 0);
            }

        }, delay);

        return () => clearTimeout(timeoutRef.current);
    }, [key, state, isHeavy]);

    return [state, setState];
}

